def pbkdf2_hash_password(password: str, salt: bytes = None, iterations: int = 210_000) -> str:
    if salt is None:
        salt = secrets.token_bytes(16)
    dk = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt, iterations, dklen=32)
    return f"pbkdf2_sha256${iterations}${base64.b64encode(salt).decode()}${base64.b64encode(dk).decode()}"


def pbkdf2_verify_password(password: str, stored: str) -> bool:
    try:
        scheme, iters_s, salt_b64, dk_b64 = stored.split("$", 3)
        if scheme != "pbkdf2_sha256":
            return False
        iterations = int(iters_s)
        salt = base64.b64decode(salt_b64.encode())
        expected = base64.b64decode(dk_b64.encode())
        dk = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt, iterations, dklen=len(expected))
        return hmac.compare_digest(dk, expected)
    except Exception:
        return False


def random_base32_secret(length_bytes: int = 20) -> str:
    return base64.b32encode(secrets.token_bytes(length_bytes)).decode("utf-8").strip("=")


def _b32decode_nopad(s: str) -> bytes:
    s = s.strip().replace(" ", "").upper()
    pad = "=" * ((8 - (len(s) % 8)) % 8)
    return base64.b32decode(s + pad)


def totp(secret_b32: str, timestep: int = 30, digits: int = 6, t: int = None) -> str:
    if t is None:
        t = int(time.time())
    counter = int(t // timestep)
    key = _b32decode_nopad(secret_b32)
    msg = counter.to_bytes(8, "big")
    hm = hmac.new(key, msg, hashlib.sha1).digest()
    offset = hm[-1] & 0x0F
    code_int = (int.from_bytes(hm[offset:offset + 4], "big") & 0x7FFFFFFF) % (10 ** digits)
    return str(code_int).zfill(digits)


def verify_totp(secret_b32: str, code: str, window: int = 1, timestep: int = 30, digits: int = 6) -> bool:
    code = (code or "").strip()
    if not (code.isdigit() and len(code) == digits):
        return False
    now = int(time.time())
    for w in range(-window, window + 1):
        if hmac.compare_digest(totp(secret_b32, timestep=timestep, digits=digits, t=now + w * timestep), code):
            return True
    return False


def is_safe_url(target: str) -> bool:
    if not target:
        return False
    ref_url = urlparse(request.host_url)
    test_url = urlparse(urljoin(request.host_url, target))
    return test_url.scheme in ("http", "https") and ref_url.netloc == test_url.netloc


