def create_user(username: str, password: str):
    mfa_secret = random_base32_secret()
    password_hash = pbkdf2_hash_password(password)
    conn = get_db()
    cur = conn.cursor()
    cur.execute(
        "INSERT INTO users (username, password_hash, mfa_secret, created_at) VALUES (?, ?, ?, ?)",
        (username, password_hash, mfa_secret, int(time.time())),
    )
    conn.commit()
    conn.close()
    return mfa_secret


def login_required(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        uid = session.get("user_id")
        if not uid:
            return redirect(url_for("login", next=request.path))
        return fn(*args, **kwargs)
    return wrapper


def mfa_required(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        uid = session.get("user_id")
        if not uid:
            return redirect(url_for("login", next=request.path))
        if not session.get("mfa_verified"):
            session["mfa_pending"] = True
            session["mfa_next"] = request.path
            return redirect(url_for("verify_mfa", next=request.path))
        return fn(*args, **kwargs)
    return wrapper


