    code = (request.form.get("code") or request.json.get("code") if request.is_json else None) or ""
    if verify_totp(user["mfa_secret"], code):
        session["mfa_verified"] = True
        session["mfa_pending"] = False
        session["mfa_verified_at"] = int(time.time())
        session.pop("mfa_next", None)
        return redirect(next_url)

    return jsonify({"ok": False, "error": "invalid_mfa_code"}), 401


